// BΟΦndel ΟΦber einen DataChannel.
AnazhRealm.P2P_BUNDLE_PULL_TIMEOUT_MS = 30000;

// W7 Phase 3 βÄî LLM-Pool. Ein Peer mit aktivem LLM teilt seine βÄûStimme",
